def dfs_iterative_adj_list_path(graph, start):
    visited = set()
    stack = [(start, [start])]
    path = []
    while stack:
        (node, current_path) = stack.pop()
        if node not in visited:
            visited.add(node)
            path = current_path
            for neighbor in graph.get(node, []):
                if neighbor not in visited:
                    stack.append((neighbor, current_path + [neighbor]))
    return path

