def bfs_functional_adj_list(graph, start_node):
    visited = {start_node}
    queue = [start_node]

    def explore(q):
        if not q: return []
        node = q.pop(0)
        neighbors = [n for n in graph.get(node,[]) if n not in visited]
        visited.update(neighbors)
        return [node] + explore(q + neighbors)

    return explore(queue)

