                heapq.heappush(queue, (distances[neighbor], neighbor))
    return distances

from functools import reduce

def dijkstra_functional(graph, start):
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    pq = [(0, start)]
    return reduce(lambda dists, (dist, node): dists if dist > dists[node] else (dists[node], dists[node] + weight) for neighbor, weight in graph[node].items() if distances[node] + weight < dists[neighbor] for _, dists in [(neighbor, dists)] if dists is not None, distances, pq)

import heapq

def dijkstra_neg_edge_check(graph, start):
    for node in graph:
        for neighbor, weight in graph[node].items():
            if weight < 0:
                raise ValueError("Negative edge weights not allowed")
    return dijkstra(graph, start)

def dijkstra_list_repr(adj_list, start):
    distances = {node: float('inf') for node in adj_list}
    distances[start] = 0
    pq = [(0, start)]
    while pq:
        dist, node = heapq.heappop(pq)
        if dist > distances[node]:
            continue
        for neighbor, weight in adj_list[node]:
            if distances[node] + weight < distances[neighbor]:
                distances[neighbor] = distances[node] + weight
                heapq.heappush(pq, (distances[neighbor], neighbor))
    return distances

import heapq

def dijkstra_with_path(graph, start, end):
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    previous = {node: None for node in graph}
    pq = [(0, start)]
    while pq:
        dist, node = heapq.heappop(pq)
        if dist > distances[node]:
            continue
        for neighbor, weight in graph[node].items():
            if distances[node] + weight < distances[neighbor]:
                distances[neighbor] = distances[node] + weight
                previous[neighbor] = node
                heapq.heappush(pq, (distances[neighbor], neighbor))
    path = []
    current = end
    while current is not None:
        path.append(current)
        current = previous[current]
    return distances, path[::-1]

import heapq

def dijkstra_sparse(graph, start):
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    pq = [(0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > distances[u]:
            continue
        if u in graph:
            for v, w in graph[u].items():
                if distances[u] + w < distances[v]:
                    distances[v] = distances[u] + w
                    heapq.heappush(pq, (distances[v], v))
    return distances

def solve_grasshopper_recursive(costs):
    n = len(costs)
    memo = {}
    path = {}

    def hop(idx):
        if idx >= n:
            return 0, []
        if idx in memo:
            return memo[idx]

        cost1, path1 = hop(idx + 1)
        cost2, path2 = hop(idx + 2)

        if cost1 + costs[idx] < cost2 + costs[idx]:
            memo[idx] = cost1 + costs[idx], [idx + 1] + path1
            return memo[idx]
        else:
            memo[idx] = cost2 + costs[idx], [idx + 2] + path2
            return memo[idx]

    result_cost, result_path = hop(0)
    return result_cost, [i + 1 for i in result_path]

def solve_grasshopper_rolling_array(costs):
    n = len(costs)
    if n < 3:
        return sum(costs), list(range(1, n + 1))

    dp = [0, costs[0], costs[1]]
    prev = [0, 1, 1]

    for i in range(2, n):
        if dp[1] + costs[i] < dp[2] + costs[i]:
            dp[0] = dp[1] + costs[i]
            prev[0] = 1
        else:
            dp[0] = dp[2] + costs[i]
            prev[0] = 2

        dp[1] = dp[0]
        dp[2] = dp[1]

    path = []
    index = n - 1
    while index >= 0:
        path.insert(0, index + 1)
        if prev[0] == 1:
            index -= 1
        else:
            index -= 2

    return dp[0], path

def solve_grasshopper_in_place(costs):
    n = len(costs)
    for i in range(2, n):
        if costs[i - 1] < costs[i - 2]:
            costs[i] += costs[i - 1]
        else:
            costs[i] += costs[i - 2]

    path = []
    i = n - 1
    while i >= 0:
        path.insert(0, i + 1)
        if i > 1 and costs[i - 1] < costs[i - 2]:
            i -= 1
        else:
            i -= 2

    return costs[n-1], path

def solve_grasshopper_generator(costs):
    def jumps(index):
        if index >= len(costs):
            yield (0, [])
        else:
            for next_index in [index + 1, index + 2]:
                for cost, path in jumps(next_index):
                    yield (cost + costs[index], [index + 1] + path)

    best_cost = float('inf')
    best_path = []
    for cost, path in jumps(0):
        if cost < best_cost:
            best_cost = cost
            best_path = path

    return best_cost, best_path

