        if index >= n:
            return 0, []
        if index in memo:
            return memo[index]

        cost1, path1 = solve(index + 1)
        cost2, path2 = solve(index + 2)

        if cost1 + path[index] < cost2 + path[index]:
            memo[index] = cost1 + path[index], [index + 1] + path1
            trace[index] = index + 1
