import multiprocessing

def turtle_dp_parallel(matrix):
    n = len(matrix)
    m = len(matrix[0]) if n > 0 else 0
    if n == 0:
        return 0, ""

    dp = [[0] * m for _ in range(n)]
    dp[0][0] = matrix[0][0]

    def process_row(row_index):
        for j in range(m):
            if row_index > 0:
                dp[row_index][j] = dp[row_index - 1][j] + matrix[row_index][j]
            elif j > 0:
                dp[row_index][j] = dp[row_index][j - 1] + matrix[row_index][j]

    with multiprocessing.Pool() as pool:
        pool.map(process_row, range(1, n))

    for i in range(1, n):
        for j in range(1, m):
            dp[i][j] = min(dp[i - 1][j], dp[i][j - 1]) + matrix[i][j]

    path = ""
    i, j = n - 1, m - 1
    while i > 0 or j > 0:
        if i > 0 and j > 0 and dp[i - 1][j] <= dp[i][j - 1]:
            path = "D" + path
            i -= 1
        else:
            path = "R" + path
            j -= 1

    return dp[n - 1][m - 1], path

def turtle_dp_recursive_memo(grid):
    rows = len(grid)
    cols = len(grid[0]) if rows > 0 else 0
    memo = {}

    def solve(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if i == rows - 1 and j == cols - 1:
            return grid[i][j], ""
        if i >= rows or j >= cols:
            return float('inf'), ""

        down_cost, down_path = solve(i + 1, j)
        right_cost, right_path = solve(i, j + 1)

        if down_cost < right_cost:
            cost = grid[i][j] + down_cost
            path = "D" + down_path
        else:
            cost = grid[i][j] + right_cost
            path = "R" + right_path

        memo[(i, j)] = (cost, path)
        return cost, path

    if not grid:
        return 0, ""
    return solve(0, 0)

