def turtle_dp_memo(grid):
    if not grid or not grid[0]:
        return 0, ""
    n, m = len(grid), len(grid[0])
    memo = {}
    def solve(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if i == n - 1 and j == m - 1:
            return grid[i][j], ""
        if i >= n or j >= m:
            return float('inf'), ""
        right_cost, right_path = solve(i, j + 1)
        down_cost, down_path = solve(i + 1, j)
        cost = grid[i][j] + min(right_cost, down_cost)
        path = "R" + right_path if right_cost <= down_cost else "D" + down_path
        memo[(i, j)] = cost, path
        return cost, path
    return solve(0, 0)

def turtle_dp_iterative(cost_matrix):
