    cols = len(grid[0]) if rows > 0 else 0
    memo = {}
    def solve(x, y):
        if (x, y) in memo:
            return memo[(x, y)]
        if x == rows - 1 and y == cols - 1:
            return grid[x][y], ''
        if x >= rows or y >= cols:
