            if i == 0 and j == 0:
                continue
            if i > 0 and j > 0:
                if cost[i-1][j] <= cost[i][j-1]:
                    cost[i][j] = cost[i-1][j] + values[i][j]
                    path[i][j] = "D"
                else:
                    cost[i][j] = cost[i][j-1] + values[i][j]
                    path[i][j] = "R"
            elif i > 0:
                cost[i][j] = cost[i-1][j] + values[i][j]
                path[i][j] = "D"
