import numpy as np

def turtle_dp_numpy(matrix):
    grid = np.array(matrix)
    rows, cols = grid.shape
    dp = np.zeros((rows, cols), dtype=int)

    dp[0, 0] = grid[0, 0]

    for i in range(1, rows):
        dp[i, 0] = dp[i-1, 0] + grid[i, 0]
    for j in range(1, cols):
        dp[0, j] = dp[0, j-1] + grid[0, j]

    for i in range(1, rows):
        for j in range(1, cols):
            dp[i, j] = grid[i, j] + min(dp[i-1, j], dp[i, j-1])

    path = ""
    i, j = rows - 1, cols - 1
    while i > 0 or j > 0:
        if i > 0 and (j == 0 or dp[i-1, j] <= dp[i, j-1]):
            path = 'D' + path
            i -= 1
        else:
            path = 'R' + path
            j -= 1

    return dp[rows-1, cols-1], path

def turtle_dp_early_exit(grid):
    rows = len(grid)
    cols = len(grid[0]) if rows else 0
    if rows == 0 or cols == 0:
        return 0, ""

    dp = [[0] * cols for _ in range(rows)]
    dp[0][0] = grid[0][0]
    for i in range(1, rows):
        dp[i][0] = dp[i-1][0] + grid[i][0]
    for j in range(1, cols):
        dp[0][j] = dp[0][j-1] + grid[0][j]

    for i in range(1, rows):
        for j in range(1, cols):
            dp[i][j] = min(dp[i-1][j], dp[i][j-1]) + grid[i][j]

    path = ""
    i, j = rows - 1, cols - 1
    while i > 0 or j > 0:
        if i > 0 and dp[i-1][j] <= dp[i][j-1]:
            path = 'D' + path
            i -= 1
        else:
            path = 'R' + path
            j -= 1

    return dp[rows-1][cols-1], path

import concurrent.futures

def turtle_dp_parallel(matrix):
    rows = len(matrix)
    cols = len(matrix[0]) if rows else 0
    if rows == 0 or cols == 0:
        return 0, ""

    dp = [[0] * cols for _ in range(rows)]
    dp[0][0] = matrix[0][0]

    for i in range(1, rows):
        dp[i][0] = dp[i-1][0] + matrix[i][0]

    for j in range(1, cols):
        dp[0][j] = dp[0][j-1] + matrix[0][j]

    with concurrent.futures.ThreadPoolExecutor() as executor:
         futures = []
         for i in range(1, rows):
               for j in range(1, cols):
                    futures.append(executor.submit(calculate_dp, matrix, dp, i, j))
         concurrent.futures.wait(futures)

    path = ""
    i, j = rows - 1, cols - 1
    while i > 0 or j > 0:
      if i > 0 and (j == 0 or dp[i-1][j] <= dp[i][j-1]):
          path = 'D' + path
          i -= 1
      else:
          path = 'R' + path
          j -= 1

    return dp[rows-1][cols-1], path

def calculate_dp(matrix, dp, i, j):
    dp[i][j] = min(dp[i-1][j], dp[i][j-1]) + matrix[i][j]

def turtle_dp_recursive(grid):
    rows = len(grid)
    cols = len(grid[0]) if rows > 0 else 0
    memo = {}

    def solve(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if i == rows - 1 and j == cols - 1:
            return grid[i][j], ""
        if i >= rows or j >= cols:
            return float('inf'), ""

        down_cost, down_path = solve(i + 1, j)
        right_cost, right_path = solve(i, j + 1)

        if down_cost < right_cost:
            memo[(i, j)] = grid[i][j] + down_cost, "D" + down_path
        else:
            memo[(i, j)] = grid[i][j] + right_cost, "R" + right_path
        return memo[(i, j)]

    if not grid:
        return 0, ""
    return solve(0, 0)

def turtle_dp_iterative(cost_matrix):
    n = len(cost_matrix)
    m = len(cost_matrix[0]) if n > 0 else 0
    dp = [[0] * m for _ in range(n)]
    path = [[''] * m for _ in range(n)]

    dp[0][0] = cost_matrix[0][0]
    for i in range(1, n):
        dp[i][0] = dp[i - 1][0] + cost_matrix[i][0]
        path[i][0] = 'D' + path[i - 1][0]
    for j in range(1, m):
        dp[0][j] = dp[0][j - 1] + cost_matrix[0][j]
        path[0][j] = 'R' + path[0][j - 1]

    for i in range(1, n):
        for j in range(1, m):
            if dp[i - 1][j] < dp[i][j - 1]:
                dp[i][j] = dp[i - 1][j] + cost_matrix[i][j]
                path[i][j] = 'D' + path[i - 1][j]
            else:
                dp[i][j] = dp[i][j - 1] + cost_matrix[i][j]
                path[i][j] = 'R' + path[i][j - 1]

    return dp[n - 1][m - 1], path[n - 1][m - 1]

def turtle_dp_in_place(grid_data):
    n = len(grid_data)
    m = len(grid_data[0]) if n > 0 else 0
    if n == 0:
        return 0, ""

    for i in range(n):
        for j in range(m):
            if i == 0 and j == 0:
                continue
            up = grid_data[i - 1][j] if i > 0 else float('inf')
            left = grid_data[i][j - 1] if j > 0 else float('inf')
            grid_data[i][j] += min(up, left)

    cost = grid_data[n - 1][m - 1]
    path = ""
    i, j = n - 1, m - 1
    while i > 0 or j > 0:
        if i > 0 and j > 0:
            if grid_data[i - 1][j] < grid_data[i][j - 1]:
                path = 'D' + path
                i -= 1
            else:
                path = 'R' + path
                j -= 1
        elif i > 0:
            path = 'D' + path
            i -= 1
        else:
            path = 'R' + path
            j -= 1

    return cost, path

def turtle_dp_parent_pointers(matrix_data):
    n = len(matrix_data)
    m = len(matrix_data[0]) if n > 0 else 0
    dp = [[0] * m for _ in range(n)]
    parent = [[None] * m for _ in range(n)]

    for i in range(n):
        for j in range(m):
            if i == 0 and j == 0:
                continue
            up_cost = dp[i - 1][j] if i > 0 else float('inf')
            left_cost = dp[i][j - 1] if j > 0 else float('inf')

            if up_cost < left_cost:
                dp[i][j] = up_cost + matrix_data[i][j]
                parent[i][j] = (i - 1, j)
            else:
                dp[i][j] = left_cost + matrix_data[i][j]
                parent[i][j] = (i, j - 1)

    path = ""
    i, j = n - 1, m - 1
    while i != 0 or j != 0:
        if parent[i][j] is None:
            break
        prev_i, prev_j = parent[i][j]
        if prev_i == i - 1:
            path = 'D' + path
        else:
            path = 'R' + path
        i, j = prev_i, prev_j

    return dp[n - 1][m - 1], path

def turtle_dp_generator(grid_input):
    n = len(grid_input)
    m = len(grid_input[0]) if n > 0 else 0

    def path_generator(i, j):
        if i == n - 1 and j == m - 1:
            yield ""
        elif i + 1 < n and j + 1 < m:
            if grid_input[i + 1][j] < grid_input[i][j + 1]:
                yield "D"
                for p in path_generator(i + 1, j):
                    yield "D" + p
            else:
                yield "R"
                for p in path_generator(i, j + 1):
                    yield "R" + p
        elif i + 1 < n:
            yield "D"
            for p in path_generator(i + 1, j):
                yield "D" + p
        elif j + 1 < m:
            yield "R"
            for p in path_generator(i, j + 1):
                yield "R" + p

    if not grid_input:
        return 0, ""

    min_cost = float('inf')
    best_path = ""
    for path in path_generator(0, 0):
        cost = 0
        curr_i, curr_j = 0, 0
        for move in path:
            cost += grid_input[curr_i][curr_j]
            if move == 'D':
                curr_i += 1
            else:
                curr_j += 1
        cost += grid_input[n - 1][m - 1]
        if cost < min_cost:
            min_cost = cost
            best_path = path

    return min_cost, best_path

from functools import reduce

def turtle_dp_reduce(matrix_data):
    n = len(matrix_data)
    m = len(matrix_data[0]) if n > 0 else 0
    if n == 0:
        return 0, ""

    dp = reduce(lambda row, i: row + [reduce(lambda col, j: col + [matrix_data[i][j] + (row[j-1] if j > 0 else 0) if i == 0 else matrix_data[i][j] + min(row[j] if j > 0 else float('inf'), row[j-1] if j > 0 else float('inf'))], [], range(m))], [], range(n))
    cost = dp[-1][-1]
    path = ""
    i, j = n - 1, m - 1
    while i > 0 or j > 0:
        if i > 0 and j > 0:
            if matrix_data[i-1][j] < matrix_data[i][j-1]:
                path = 'D' + path
                i -= 1
            else:
                path = 'R' + path
                j -= 1
        elif i > 0:
            path = 'D' + path
            i -= 1
        else:
            path = 'R' + path
            j -= 1
    return cost, path

import numpy as np

def turtle_dp_numpy(grid_matrix):
    grid = np.array(grid_matrix)
    n, m = grid.shape
    dp = np.zeros((n, m), dtype=int)
    dp[0, 0] = grid[0, 0]

    for i in range(1, n):
        dp[i, 0] = dp[i - 1, 0] + grid[i, 0]
    for j in range(1, m):
        dp[0, j] = dp[0, j - 1] + grid[0, j]

    for i in range(1, n):
        for j in range(1, m):
            dp[i, j] = grid[i, j] + min(dp[i - 1, j], dp[i, j - 1])

    path = ""
    i, j = n - 1, m - 1
    while i > 0 or j > 0:
        if i > 0 and j > 0:
            if dp[i - 1, j] < dp[i, j - 1]:
                path = 'D' + path
                i -= 1
            else:
                path = 'R' + path
                j -= 1
        elif i > 0:
            path = 'D' + path
            i -= 1
        else:
            path = 'R' + path
            j -= 1

    return dp[n - 1, m - 1], path

def turtle_dp_early_exit(matrix_data):
    n = len(matrix_data)
    m = len(matrix_data[0]) if n > 0 else 0
    dp = [[0] * m for _ in range(n)]
    path = [[''] * m for _ in range(n)]

    dp[0][0] = matrix_data[0][0]
    for i in range(1, n):
        dp[i][0] = dp[i - 1][0] + matrix_data[i][0]
        path[i][0] = 'D' + path[i - 1][0]
    for j in range(1, m):
        dp[0][j] = dp[0][j - 1] + matrix_data[0][j]
        path[0][j] = 'R' + path[0][j - 1]

    for i in range(1, n):
        for j in range(1, m):
            if dp[i - 1][j] < dp[i][j - 1]:
                dp[i][j] = dp[i - 1][j] + matrix_data[i][j]
                path[i][j] = 'D' + path[i - 1][j]
            else:
                dp[i][j] = dp[i][j - 1] + matrix_data[i][j]
                path[i][j] = 'R' + path[i][j - 1]

    return dp[n - 1][m - 1], path[n - 1][m - 1]
